76	inline unsigned int mkhash_xorshift(unsigned int a) {
77		if (sizeof(a) == 4) {
78			a ^= a << 13;
79			a ^= a >> 17;
80			a ^= a << 5;
81		} else if (sizeof(a) == 8) {
82			a ^= a << 13;
83			a ^= a >> 7;
84			a ^= a << 17;
85		} else
86			throw std::runtime_error("mkhash_xorshift() only implemented for 32 bit and 64 bit ints");
87		return a;
88	}
