90	class HasherDJB32 {
91	public:
92		using hash_t = uint32_t;
93	
94		HasherDJB32() {
95			// traditionally 5381 is used as starting value for the djb2 hash
96			state = 5381;
97		}
98		static void set_fudge(hash_t f) {
99			fudge = f;
100		}
101	
102	private:
103		uint32_t state;
104		static uint32_t fudge;
105		// The XOR version of DJB2
106		[[nodiscard]]
107		static uint32_t djb2_xor(uint32_t a, uint32_t b) {
108			uint32_t hash = ((a << 5) + a) ^ b;
109			return hash;
110		}
111	public:
112		void hash32(uint32_t i) {
113			state = djb2_xor(i, state);
114			state = mkhash_xorshift(fudge ^ state);
115			return;
116		}
117		void hash64(uint64_t i) {
118			state = djb2_xor((uint32_t)(i & 0xFFFFFFFFULL), state);
119			state = djb2_xor((uint32_t)(i >> 32ULL), state);
120			state = mkhash_xorshift(fudge ^ state);
121			return;
122		}
123		[[nodiscard]]
124		hash_t yield() const {
125			return (hash_t)state;
126		}
127	
128		template<typename T>
129		void eat(T&& t) {
130			*this = hash_ops<std::remove_cv_t<std::remove_reference_t<T>>>::hash_into(std::forward<T>(t), *this);
131		}
132	
133		template<typename T>
134		void eat(const T& t) {
135			*this = hash_ops<T>::hash_into(t, *this);
136		}
137	
138		[[deprecated]]
139		void commutative_eat(hash_t t) {
140			state ^= t;
141		}
142	
143		void force(hash_t new_state) {
144			state = new_state;
145		}
146	};
