150	// Boilerplate compressor for trivially implementing
151	// top-level hash method with hash_into
152	#define HASH_TOP_LOOP_FST [[nodiscard]] static inline Hasher hash
153	#define HASH_TOP_LOOP_SND { \
154		Hasher h; \
155		h = hash_into(a, h); \
156		return h; \
157	}
