159	template<typename T>
160	struct hash_ops {
161		static inline bool cmp(const T &a, const T &b) {
162			return a == b;
163		}
164		[[nodiscard]] static inline Hasher hash_into(const T &a, Hasher h) {
165			if constexpr (std::is_integral_v<T>) {
166				static_assert(sizeof(T) <= sizeof(uint64_t));
167				if (sizeof(T) == sizeof(uint64_t))
168					h.hash64(a);
169				else
170					h.hash32(a);
171				return h;
172			} else if constexpr (std::is_enum_v<T>) {
173				using u_type = std::underlying_type_t<T>;
174				return hash_ops<u_type>::hash_into((u_type) a, h);
175			} else if constexpr (std::is_pointer_v<T>) {
176				return hash_ops<uintptr_t>::hash_into((uintptr_t) a, h);
177			} else if constexpr (std::is_same_v<T, std::string>) {
178				int size = a.size();
179				int i = 0;
180				while (i + 8 < size) {
181					uint64_t v;
182					memcpy(&v, a.data() + i, 8);
183					h.hash64(v);
184					i += 8;
185				}
186				uint64_t v = 0;
187				memcpy(&v, a.data() + i, size - i);
188				h.hash64(v);
189				return h;
190			} else {
191				return a.hash_into(h);
192			}
193		}
194		HASH_TOP_LOOP_FST (const T &a) HASH_TOP_LOOP_SND
195	};
