197	template<typename P, typename Q> struct hash_ops<std::pair<P, Q>> {
198		static inline bool cmp(const std::pair<P, Q> &a, const std::pair<P, Q> &b) {
199			return a == b;
200		}
201		[[nodiscard]] static inline Hasher hash_into(const std::pair<P, Q> &a, Hasher h) {
202			h = hash_ops<P>::hash_into(a.first, h);
203			h = hash_ops<Q>::hash_into(a.second, h);
204			return h;
205		}
206		HASH_TOP_LOOP_FST (const std::pair<P, Q> &a) HASH_TOP_LOOP_SND
207		[[nodiscard]] static inline Hasher hash(const P &p, const Q &q) {
208			Hasher h;
209			h = hash_ops<P>::hash_into(p, h);
210			h = hash_ops<Q>::hash_into(q, h);
211			return h;
212		}
213	};
