215	template<typename... T> struct hash_ops<std::tuple<T...>> {
216		static inline bool cmp(const std::tuple<T...> &a, const std::tuple<T...> &b) {
217			return a == b;
218		}
219		template<size_t I = 0>
220		static inline typename std::enable_if<I == sizeof...(T), Hasher>::type hash_into(const std::tuple<T...> &, Hasher h) {
221			return h;
222		}
223		template<size_t I = 0>
224		static inline typename std::enable_if<I != sizeof...(T), Hasher>::type hash_into(const std::tuple<T...> &a, Hasher h) {
225			typedef hash_ops<typename std::tuple_element<I, std::tuple<T...>>::type> element_ops_t;
226			h = hash_into<I+1>(a, h);
227			h = element_ops_t::hash_into(std::get<I>(a), h);
228			return h;
229		}
230		HASH_TOP_LOOP_FST (const std::tuple<T...> &a) HASH_TOP_LOOP_SND
