233	template<typename T> struct hash_ops<std::vector<T>> {
234		static inline bool cmp(const std::vector<T> &a, const std::vector<T> &b) {
235			return a == b;
236		}
237		[[nodiscard]] static inline Hasher hash_into(const std::vector<T> &a, Hasher h) {
238			h.eat((uint32_t)a.size());
239			for (auto k : a)
240				h.eat(k);
241			return h;
242		}
