350	inline unsigned int hashtable_size(unsigned int min_size)
351	{
352		// Primes as generated by https://oeis.org/A175953
353		static std::vector<unsigned int> zero_and_some_primes = {
354			0, 23, 29, 37, 47, 59, 79, 101, 127, 163, 211, 269, 337, 431, 541, 677,
355			853, 1069, 1361, 1709, 2137, 2677, 3347, 4201, 5261, 6577, 8231, 10289,
356			12889, 16127, 20161, 25219, 31531, 39419, 49277, 61603, 77017, 96281,
357			120371, 150473, 188107, 235159, 293957, 367453, 459317, 574157, 717697,
358			897133, 1121423, 1401791, 1752239, 2190299, 2737937, 3422429, 4278037,
359			5347553, 6684443, 8355563, 10444457, 13055587, 16319519, 20399411,
360			25499291, 31874149, 39842687, 49803361, 62254207, 77817767, 97272239,
361			121590311, 151987889, 189984863, 237481091, 296851369, 371064217,
362			463830313, 579787991, 724735009, 905918777, 1132398479, 1415498113,
363			1769372713, 2211715897, 2764644887, 3455806139
364		};
365	
366		for (auto p : zero_and_some_primes)
367			if (p >= min_size) return p;
368	
369		if (sizeof(unsigned int) == 4)
370			throw std::length_error("hash table exceeded maximum size.\nDesign is likely too large for yosys to handle, if possible try not to flatten the design.");
371	
372		for (auto p : zero_and_some_primes)
373			if (100129 * p > min_size) return 100129 * p;
374	
375		throw std::length_error("hash table exceeded maximum size.");
376	}
