383	// Computes the hash value of an unordered set of elements.
384	// See https://www.preprints.org/manuscript/201710.0192/v1/download.
385	// This is the Sum(4) algorithm from that paper, which has good collision resistance,
386	// much better than Sum(1) or Xor(1) (and somewhat better than Xor(4)).
387	class commutative_hash {
388	public:
389		commutative_hash() {
390			buckets.fill(0);
391		}
392		template <typename T>
393		void eat(const T &obj) {
394			eat(hash_ops<T>::hash(obj));
395		}
396		void eat(const Hasher &h) {
397			Hasher::hash_t v = h.yield();
398			size_t index = v & (buckets.size() - 1);
399			buckets[index] += v;
400		}
401		[[nodiscard]] Hasher hash_into(Hasher h) const {
402			for (auto b : buckets)
403				h.eat(b);
404			return h;
405		}
406	private:
407		std::array<Hasher::hash_t, 4> buckets;
408	};
