410	template<typename K, typename T, typename OPS>
411	class HASHLIB_ATTRIBUTE_WARN_UNUSED dict {
412		struct entry_t
413		{
414			std::pair<K, T> udata;
415			int next;
416	
417			entry_t() { }
418			entry_t(const std::pair<K, T> &udata, int next) : udata(udata), next(next) { }
419			entry_t(std::pair<K, T> &&udata, int next) : udata(std::move(udata)), next(next) { }
420			bool operator<(const entry_t &other) const { return udata.first < other.udata.first; }
421		};
422	
423		std::vector<int> hashtable;
424		std::vector<entry_t> entries;
425		OPS ops;
426	
427	#ifdef NDEBUG
428		static inline void do_assert(bool) { }
429	#else
430		static inline void do_assert(bool cond) {
431			if (!cond) throw std::runtime_error("dict<> assert failed.");
432		}
433	#endif
434	
435		Hasher::hash_t do_hash(const K &key) const
436		{
437			Hasher::hash_t hash = 0;
438			if (!hashtable.empty())
439				hash = ops.hash(key).yield() % (unsigned int)(hashtable.size());
440			return hash;
441		}
442	
443		void do_rehash()
444		{
445			hashtable.clear();
446			hashtable.resize(hashtable_size(entries.capacity() * hashtable_size_factor), -1);
447	
448			for (int i = 0; i < int(entries.size()); i++) {
449				do_assert(-1 <= entries[i].next && entries[i].next < int(entries.size()));
450				Hasher::hash_t hash = do_hash(entries[i].udata.first);
451				entries[i].next = hashtable[hash];
452				hashtable[hash] = i;
453			}
454		}
455	
456		int do_erase(int index, Hasher::hash_t hash)
457		{
458			do_assert(index < int(entries.size()));
459			if (hashtable.empty() || index < 0)
460				return 0;
461	
462			int k = hashtable[hash];
463			do_assert(0 <= k && k < int(entries.size()));
464	
465			if (k == index) {
466				hashtable[hash] = entries[index].next;
467			} else {
468				while (entries[k].next != index) {
469					k = entries[k].next;
470					do_assert(0 <= k && k < int(entries.size()));
471				}
472				entries[k].next = entries[index].next;
473			}
474	
475			int back_idx = entries.size()-1;
476	
477			if (index != back_idx)
478			{
479				Hasher::hash_t back_hash = do_hash(entries[back_idx].udata.first);
480	
481				k = hashtable[back_hash];
482				do_assert(0 <= k && k < int(entries.size()));
483	
484				if (k == back_idx) {
485					hashtable[back_hash] = index;
486				} else {
487					while (entries[k].next != back_idx) {
488						k = entries[k].next;
489						do_assert(0 <= k && k < int(entries.size()));
490					}
491					entries[k].next = index;
492				}
493	
494				entries[index] = std::move(entries[back_idx]);
495			}
496	
497			entries.pop_back();
498	
499			if (entries.empty())
500				hashtable.clear();
501	
502			return 1;
503		}
504	
505		int do_lookup(const K &key, Hasher::hash_t &hash)
506		{
507			if (hashtable.empty())
508				return -1;
509	
510			if (entries.size() * hashtable_size_trigger > hashtable.size()) {
511				do_rehash();
512				hash = do_hash(key);
513			}
514	
515			return do_lookup_internal(key, hash);
516		}
517	
518		int do_lookup_internal(const K &key, Hasher::hash_t hash) const
519		{
520			int index = hashtable[hash];
521	
522			while (index >= 0 && !ops.cmp(entries[index].udata.first, key)) {
523				index = entries[index].next;
524				do_assert(-1 <= index && index < int(entries.size()));
525			}
526	
527			return index;
528		}
529	
530		int do_lookup_no_rehash(const K &key, Hasher::hash_t hash) const
531		{
532			if (hashtable.empty())
533				return -1;
534	
535			return do_lookup_internal(key, hash);
536		}
537	
538		int do_insert(const K &key, const Hasher::hash_t &hash)
539		{
540			if (hashtable.empty()) {
541				entries.emplace_back(std::pair<K, T>(key, T()), -1);
542				do_rehash();
543			} else {
544				entries.emplace_back(std::pair<K, T>(key, T()), hashtable[hash]);
545				hashtable[hash] = entries.size() - 1;
546			}
547			return entries.size() - 1;
548		}
549	
550		int do_insert(const std::pair<K, T> &value, const Hasher::hash_t &hash)
551		{
552			if (hashtable.empty()) {
553				entries.emplace_back(value, -1);
554				do_rehash();
555			} else {
556				entries.emplace_back(value, hashtable[hash]);
557				hashtable[hash] = entries.size() - 1;
558			}
559			return entries.size() - 1;
560		}
561	
562		int do_insert(std::pair<K, T> &&rvalue, const Hasher::hash_t &hash)
563		{
564			if (hashtable.empty()) {
565				entries.emplace_back(std::forward<std::pair<K, T>>(rvalue), -1);
566				do_rehash();
567			} else {
568				entries.emplace_back(std::forward<std::pair<K, T>>(rvalue), hashtable[hash]);
569				hashtable[hash] = entries.size() - 1;
570			}
571			return entries.size() - 1;
572		}
