574	public:
575		class const_iterator
576		{
577			friend class dict;
578		protected:
579			const dict *ptr;
580			int index;
581			const_iterator(const dict *ptr, int index) : ptr(ptr), index(index) { }
582		public:
583			typedef std::bidirectional_iterator_tag iterator_category;
584			typedef std::pair<K, T> value_type;
585			typedef ptrdiff_t difference_type;
586			typedef const std::pair<K, T>* pointer;
587			typedef const std::pair<K, T>& reference;
588			const_iterator() { }
589			const_iterator operator++() { index--; return *this; }
590			const_iterator operator++(int) { const_iterator tmp = *this; index--; return tmp; }
591			const_iterator operator--() { index++; return *this; }
592			const_iterator operator--(int) { const_iterator tmp = *this; index++; return tmp; }
593			const_iterator operator+=(int amt) { index -= amt; return *this; }
594			bool operator<(const const_iterator &other) const { return index > other.index; }
595			bool operator==(const const_iterator &other) const { return index == other.index; }
