913		Hasher::hash_t do_hash(const K &key) const
914		{
915			Hasher::hash_t hash = 0;
916			if (!hashtable.empty())
917				hash = ops.hash(key).yield() % (unsigned int)(hashtable.size());
918			return hash;
919		}
920	
921		void do_rehash()
922		{
923			hashtable.clear();
924			hashtable.resize(hashtable_size(entries.capacity() * hashtable_size_factor), -1);
925	
926			for (int i = 0; i < int(entries.size()); i++) {
927				do_assert(-1 <= entries[i].next && entries[i].next < int(entries.size()));
928				Hasher::hash_t hash = do_hash(entries[i].udata);
929				entries[i].next = hashtable[hash];
930				hashtable[hash] = i;
931			}
932		}
933	
934		int do_erase(int index, Hasher::hash_t hash)
935		{
936			do_assert(index < int(entries.size()));
937			if (hashtable.empty() || index < 0)
938				return 0;
939	
940			int k = hashtable[hash];
941			if (k == index) {
942				hashtable[hash] = entries[index].next;
943			} else {
944				while (entries[k].next != index) {
945					k = entries[k].next;
946					do_assert(0 <= k && k < int(entries.size()));
947				}
948				entries[k].next = entries[index].next;
949			}
950	
951			int back_idx = entries.size()-1;
952	
953			if (index != back_idx)
954			{
955				Hasher::hash_t back_hash = do_hash(entries[back_idx].udata);
956	
957				k = hashtable[back_hash];
958				if (k == back_idx) {
959					hashtable[back_hash] = index;
960				} else {
961					while (entries[k].next != back_idx) {
962						k = entries[k].next;
963						do_assert(0 <= k && k < int(entries.size()));
964					}
965					entries[k].next = index;
966				}
967	
968				entries[index] = std::move(entries[back_idx]);
969			}
970	
971			entries.pop_back();
972	
973			if (entries.empty())
974				hashtable.clear();
975	
976			return 1;
977		}
