979		int do_lookup(const K &key, Hasher::hash_t &hash)
980		{
981			if (hashtable.empty())
982				return -1;
983	
984			if (entries.size() * hashtable_size_trigger > hashtable.size()) {
985				do_rehash();
986				hash = do_hash(key);
987			}
988	
989			return do_lookup_internal(key, hash);
990		}
991	
992		int do_lookup_internal(const K &key, Hasher::hash_t hash) const
993		{
994			int index = hashtable[hash];
995	
996			while (index >= 0 && !ops.cmp(entries[index].udata, key)) {
997				index = entries[index].next;
998				do_assert(-1 <= index && index < int(entries.size()));
999			}
1000	
1001			return index;
1002		}
1003	
1004		int do_lookup_no_rehash(const K &key, Hasher::hash_t hash) const
1005		{
1006			if (hashtable.empty())
1007				return -1;
1008	
1009			return do_lookup_internal(key, hash);
1010		}
