1012		int do_insert(const K &value, Hasher::hash_t &hash)
1013		{
1014			if (hashtable.empty()) {
1015				entries.emplace_back(value, -1);
1016				do_rehash();
1017				hash = do_hash(value);
1018			} else {
1019				entries.emplace_back(value, hashtable[hash]);
1020				hashtable[hash] = entries.size() - 1;
1021			}
1022			return entries.size() - 1;
1023		}
