1027			if (hashtable.empty()) {
1028				entries.emplace_back(std::forward<K>(rvalue), -1);
1029				do_rehash();
1030				hash = do_hash(entries.back().udata);
1031			} else {
1032				entries.emplace_back(std::forward<K>(rvalue), hashtable[hash]);
1033				hashtable[hash] = entries.size() - 1;
1034			}
1035			return entries.size() - 1;
1036		}
