1230		bool operator==(const pool &other) const {
1231			if (size() != other.size())
1232				return false;
1233			for (auto &it : entries)
1234				if (!other.count(it.udata))
1235					return false;
1236			return true;
1237		}
1238	
1239		bool operator!=(const pool &other) const {
1240			return !operator==(other);
1241		}
1242	
1243		[[nodiscard]] Hasher hash_into(Hasher h) const {
1244			commutative_hash comm;
1245			for (auto &it : entries) {
1246				comm.eat(ops.hash(it.udata));
1247			}
1248			return comm.hash_into(h);
1249		}
1250	
1251		void reserve(size_t n) { entries.reserve(n); }
1252		size_t size() const { return entries.size(); }
1253		bool empty() const { return entries.empty(); }
1254		void clear() { hashtable.clear(); entries.clear(); }
1255	
1256		iterator begin() { return iterator(this, int(entries.size())-1); }
1257		iterator element(int n) { return iterator(this, int(entries.size())-1-n); }
1258		iterator end() { return iterator(nullptr, -1); }
1259	
1260		const_iterator begin() const { return const_iterator(this, int(entries.size())-1); }
1261		const_iterator element(int n) const { return const_iterator(this, int(entries.size())-1-n); }
1262		const_iterator end() const { return const_iterator(nullptr, -1); }
1263	};
1264	
1265	template<typename K, int offset, typename OPS>
1266	class HASHLIB_ATTRIBUTE_WARN_UNUSED idict
1267	{
1268		pool<K, OPS> database;
1269	
1270	public:
1271		class const_iterator
1272		{
1273			friend class idict;
1274		protected:
1275			const idict &container;
1276			int index;
1277			const_iterator(const idict &container, int index) : container(container), index(index) { }
1278		public:
1279			typedef std::forward_iterator_tag iterator_category;
1280			typedef K value_type;
1281			typedef ptrdiff_t difference_type;
1282			typedef K* pointer;
1283			typedef K& reference;
1284			const_iterator() { }
1285			const_iterator operator++() { index++; return *this; }
1286			bool operator==(const const_iterator &other) const { return index == other.index; }
1287			bool operator!=(const const_iterator &other) const { return index != other.index; }
1288			const K &operator*() const { return container[index]; }
1289			const K *operator->() const { return &container[index]; }
1290		};
1291	
1292		constexpr idict()
1293		{
1294		}
1295	
1296		int operator()(const K &key)
1297		{
1298			Hasher::hash_t hash = database.do_hash(key);
1299			int i = database.do_lookup(key, hash);
1300			if (i < 0)
1301				i = database.do_insert(key, hash);
1302			return i + offset;
1303		}
1304	
1305		int at(const K &key) const
1306		{
1307			Hasher::hash_t hash = database.do_hash(key);
1308			int i = database.do_lookup_no_rehash(key, hash);
1309			if (i < 0)
1310				throw std::out_of_range("idict::at()");
1311			return i + offset;
1312		}
1313	
1314		int at(const K &key, int defval) const
1315		{
1316			Hasher::hash_t hash = database.do_hash(key);
1317			int i = database.do_lookup_no_rehash(key, hash);
1318			if (i < 0)
1319				return defval;
1320			return i + offset;
1321		}
1322	
1323		int count(const K &key) const
1324		{
1325			Hasher::hash_t hash = database.do_hash(key);
1326			int i = database.do_lookup_no_rehash(key, hash);
1327			return i < 0 ? 0 : 1;
1328		}
1329	
1330		int lookup(const K &key) const
1331		{
1332			Hasher::hash_t hash = database.do_hash(key);
1333			return database.do_lookup_no_rehash(key, hash);
1334		}
1335	
1336		void expect(const K &key, int i)
1337		{
1338			int j = (*this)(key);
1339			if (i != j)
1340				throw std::out_of_range("idict::expect()");
