1362	
1363	/**
1364	 * Union-find data structure with a promotion method
1365	 * mfp stands for "merge, find, promote"
1366	 * i-prefixed methods operate on indices in parents
1367	*/
1368	template<typename K, typename OPS>
1369	class HASHLIB_ATTRIBUTE_WARN_UNUSED mfp
1370	{
1371		idict<K, 0, OPS> database;
1372		class AtomicParent {
1373		public:
1374			explicit AtomicParent(int p) : parent(p) {}
1375			AtomicParent(const AtomicParent &other) : parent(other.get()) {}
1376			AtomicParent &operator=(const AtomicParent &other) { set(other.get()); return *this; }
1377			int get() const { return parent.load(std::memory_order_relaxed); }
1378			void set(int p) { parent.store(p, std::memory_order_relaxed); }
1379		private:
1380			std::atomic<int> parent;
1381		};
1382		std::vector<AtomicParent> parents;
1383	
1384	public:
1385		typedef typename idict<K, 0>::const_iterator const_iterator;
1386	
1387		constexpr mfp()
1388		{
1389		}
1390	
1391		// Finds a given element's index. If it isn't in the data structure,
1392		// it is added as its own set
1393		int operator()(const K &key)
1394		{
1395			int i = database(key);
1396			// If the lookup caused the database to grow,
1397			// also add a corresponding entry in parents initialized to -1 (no parent)
1398			if (parents.size() < database.size()) {
1399				parents.emplace_back(-1);
1400			}
1401			return i;
1402		}
1403	
1404		// Finds an element at given index
1405		const K &operator[](int index) const
1406		{
1407			return database[index];
1408		}
1409	
1410		// Why this method is correct for concurent ifind() calls:
1411		// Consider the mfp state after the last non-const method call before
1412		// a particular call to ifind(i). In this state, i's parent chain leads
1413		// to some root R. Let S be the set of integers s such that ifind(s) = R
1414		// in this state. Let 'orig_parents' be the value of 'parents' in this state.
1415		//
1416		// Now consider the concurrent calls to ifind(s), s ∈ S, before the next non-const method
1417		// call. Consider the atomic writes performed by various ifind() calls, in any causally
1418		// consistent order. The first atomic write can only set parents[k] to R, because the
1419		// atomic read of parents[p] in the first while loop can only observe the value
1420		// 'orig_parents[p]'. Subsequent writes can also only set parents[k] to R, because the
1421		// parents[p] reads either observe 'orig_parents[p]' or R (and observing R ends the first
1422		// while loop immediately). Thus all parents[p] reads observe either 'orig_parents[p]'
1423		// or R, so ifind() always returns R.
1424		int ifind(int i) const
1425		{
1426			int p = i, k = i;
1427	
1428			while (true) {
1429				int pp = parents[p].get();
1430				if (pp < 0)
1431					break;
1432				p = pp;
1433			}
1434			// p is now the representative of i
1435			// Now we traverse from i up to the representative again
1436			// and make p the parent of all the nodes along the way.
1437			// This is a side effect and doesn't affect the return value.
1438			// It speeds up future find operations
1439			while (k != p) {
1440				int next_k = parents[k].get();
1441				const_cast<AtomicParent*>(&parents[k])->set(p);
1442				k = next_k;
1443			}
1444	
1445			return p;
1446		}
1447	
1448		// Merge sets if the given indices belong to different sets.
1449		// Makes ifind(j) the root of the merged set.
1450		void imerge(int i, int j)
1451		{
1452			i = ifind(i);
1453			j = ifind(j);
1454	
1455			if (i != j)
1456				parents[i].set(j);
1457		}
1458	
1459		void ipromote(int i)
1460		{
1461			int k = i;
1462	
1463			while (k != -1) {
1464				int next_k = parents[k].get();
1465				parents[k].set(i);
1466				k = next_k;
1467			}
1468	
1469			parents[i].set(-1);
1470		}
1471	
1472		int lookup(const K &a)
1473		{
1474			return ifind((*this)(a));
1475		}
1476	
1477		const K &find(const K &a) const
1478		{
1479			int i = database.at(a, -1);
1480			if (i < 0)
1481				return a;
1482			return (*this)[ifind(i)];
1483		}
1484	
1485		void merge(const K &a, const K &b)
1486		{
1487			imerge((*this)(a), (*this)(b));
1488		}
1489	
1490		void promote(const K &a)
1491		{
1492			int i = database.at(a, -1);
1493			if (i >= 0)
1494				ipromote(i);
1495		}
1496	
1497		void swap(mfp &other)
1498		{
1499			database.swap(other.database);
1500			parents.swap(other.parents);
1501		}
1502	
1503		void reserve(size_t n) { database.reserve(n); }
1504		size_t size() const { return database.size(); }
1505		bool empty() const { return database.empty(); }
1506		void clear() { database.clear(); parents.clear(); }
1507	
1508		const_iterator begin() const { return database.begin(); }
1509		const_iterator element(int n) const { return database.element(n); }
1510		const_iterator end() const { return database.end(); }
1511	};
1512	
1513	} /* namespace hashlib */
1514	
1515	#endif
