703	{
704		int low = 0;
705		int high = sizeof(IdTable) / sizeof(IdTable[0]);
706		while (high - low >= 2) {
707			int mid = (low + high) / 2;
708			if (name < IdTable[mid].name)
709				high = mid;
710			else
711				low = mid;
712		}
