553	int RTLIL::Const::as_int(bool is_signed) const
554	{
555		int32_t ret = 0;
556		if (const std::string *s = get_if_str()) {
557			int size = GetSize(*s);
558			// Ignore any bytes after the first 4 since bits beyond 32 are truncated.
559			for (int i = std::min(4, size); i > 0; i--)
560				ret |= static_cast<unsigned char>((*s)[size - i]) << ((i - 1) * 8);
561			// If is_signed and the string is shorter than 4 bytes then apply sign extension.
562			if (is_signed && size > 0 && size < 4 && ((*s)[0] & 0x80))
563				ret |= UINT32_MAX << size*8;
564			return ret;
565		}
566	
567		const bitvectype& bv = get_bits();
568		int significant_bits = std::min(GetSize(bv), 32);
569		for (int i = 0; i < significant_bits; i++)
570			if (bv[i] == State::S1)
571				ret |= 1 << i;
572		if (is_signed && significant_bits > 0 && significant_bits < 32 && bv.back() == State::S1 )
573			ret |= UINT32_MAX << significant_bits;
574		return ret;
575	}
576	
577	bool RTLIL::Const::convertible_to_int(bool is_signed) const
578	{
579		auto size = get_min_size(is_signed);
580	
581		if (size < 0)
582			return false;
583	
584		// If it fits in 31 bits it is definitely convertible
585		if (size <= 31)
586			return true;
587	
588		// If it fits in 32 bits, it is convertible if signed or if unsigned and the
589		// leading bit is not 1
590		if (size == 32) {
591			if (is_signed)
592				return true;
593			return back() != State::S1;
594		}
595	
596		return false;
597	}
598	
599	std::optional<int> RTLIL::Const::try_as_int(bool is_signed) const
600	{
601		if (!convertible_to_int(is_signed))
602			return std::nullopt;
603		return as_int(is_signed);
604	}
605	
606	int RTLIL::Const::as_int_saturating(bool is_signed) const
607	{
608		if (!convertible_to_int(is_signed)) {
609			if (!is_signed)
610				return std::numeric_limits<int>::max();
611	
612			const auto min_size = get_min_size(is_signed);
613			log_assert(min_size > 0);
614			const auto neg = (*this)[min_size - 1];
615			return neg ? std::numeric_limits<int>::min() : std::numeric_limits<int>::max();
616		}
617		return as_int(is_signed);
618	}
