85	{
86		ensure_prepopulated();
87	
88		log_assert(p[0] == '$' || p[0] == '\\');
89		for (char ch : p)
90			if ((unsigned)ch <= (unsigned)' ')
91				log_error("Found control character or space (0x%02x) in string '%s' which is not allowed in RTLIL identifiers\n", ch, std::string(p).c_str());
92	
93		if (p.substr(0, 6) == "$auto$") {
94			size_t autoidx_pos = p.find_last_of('$') + 1;
95			std::optional<int> p_autoidx = parse_autoidx(p.substr(autoidx_pos));
96			if (p_autoidx.has_value()) {
97				auto autoidx_it = global_autoidx_id_storage_.find(-*p_autoidx);
98				if (autoidx_it != global_autoidx_id_storage_.end() &&
99						p.substr(0, autoidx_pos) == *autoidx_it->second.prefix)
100					return -*p_autoidx;
101				// Ensure NEW_ID/NEW_ID_SUFFIX will not create collisions with the ID
102				// we're about to create.
103				autoidx.ensure_at_least(*p_autoidx + 1);
104			}
105		}
106	
107		if (global_free_idx_list_.empty()) {
108			log_assert(global_id_storage_.size() < 0x40000000);
109			global_free_idx_list_.push_back(global_id_storage_.size());
110			global_id_storage_.push_back({nullptr, 0});
111		}
112	
113		int idx = global_free_idx_list_.back();
114		global_free_idx_list_.pop_back();
115		char* buf = static_cast<char*>(malloc(p.size() + 1));
116		memcpy(buf, p.data(), p.size());
117		buf[p.size()] = 0;
118		global_id_storage_.at(idx) = {buf, GetSize(p)};
119		global_id_index_.insert(it, {std::string_view(buf, p.size()), idx});
